#!/usr/bin/env node
// Generate src/services/llm-config.ts from .dev.vars or .env.production
// Used by the client to call the LLM endpoint directly from the browser.
// Writes a simple TypeScript module that exports the LLM config.

const fs = require('fs');
const path = require('path');

// Read config from .env.production (gitignored, generated by CI/developer)
// Fall back to .dev.vars for local dev
const envFiles = ['.env.production', '.dev.vars'];
let vars = {};

for (const file of envFiles) {
  const filePath = path.join(process.cwd(), file);
  if (fs.existsSync(filePath)) {
    const content = fs.readFileSync(filePath, 'utf8');
    for (const line of content.split('\n')) {
      const eq = line.indexOf('=');
      if (eq > 0) {
        vars[line.slice(0, eq).trim()] = line.slice(eq + 1).trim();
      }
    }
    break;
  }
}

const baseUrl = vars.LLM_BASE_URL || 'https://api.openai.com/v1/chat/completions';
const apiKey = vars.LLM_API_KEY || '';
const model = vars.LLM_MODEL || 'gpt-5.4-mini';

const code = `// AUTO-GENERATED by scripts/gen-client-config.cjs — DO NOT EDIT
// LLM endpoint config for client-side direct calls

export const LLM_BASE_URL = ${JSON.stringify(baseUrl)};
export const LLM_API_KEY = ${JSON.stringify(apiKey)};
export const LLM_MODEL = ${JSON.stringify(model)};
`;

const outFile = path.join(process.cwd(), 'src', 'services', 'llm-config.ts');
fs.writeFileSync(outFile, code, 'utf8');
console.log(`Generated src/services/llm-config.ts (baseUrl: ${baseUrl}, model: ${model})`);
